import { createTwoFilesPatch, parsePatch } from 'diff';
import { DiffFile } from '../types.js';

export class DiffParser {
  parse(diffText: string): DiffFile[] {
    const files: DiffFile[] = [];
    
    try {
      const patches = parsePatch(diffText);
      
      for (const patch of patches) {
        if (!patch.oldFileName || !patch.newFileName) {
          continue; // Skip header-only patches
        }

        const status = this.getStatus(patch.oldFileName, patch.newFileName);
        const changes = this.calculateChanges(patch);
        
        files.push({
          path: this.normalizePath(patch.newFileName),
          oldPath: this.normalizePath(patch.oldFileName),
          status,
          diff: this.formatPatch(patch),
          changes,
        });
      }
    } catch (error) {
      throw new Error(`Failed to parse diff: ${error instanceof Error ? error.message : 'Unknown error'}`);
    }

    return files;
  }

  private getStatus(oldFileName: string, newFileName: string): 'added' | 'modified' | 'removed' | 'renamed' {
    if (oldFileName === '/dev/null' && newFileName !== '/dev/null') {
      return 'added';
    } else if (oldFileName !== '/dev/null' && newFileName === '/dev/null') {
      return 'removed';
    } else if (oldFileName !== newFileName) {
      return 'renamed';
    } else {
      return 'modified';
    }
  }

  private calculateChanges(patch: any) {
    let added = 0;
    let removed = 0;
    let modified = 0;

    for (const hunk of patch.hunks) {
      for (const line of hunk.lines) {
        if (line.startsWith('+') && !line.startsWith('++')) {
          added++;
        } else if (line.startsWith('-') && !line.startsWith('--')) {
          removed++;
        } else if (line.startsWith('@@')) {
          modified++;
        }
      }
    }

    return { added, removed, modified };
  }

  private formatPatch(patch: any): string {
    const lines: string[] = [];
    
    // Add header
    lines.push(`--- ${patch.oldFileName}`);
    lines.push(`+++ ${patch.newFileName}`);
    lines.push('');
    
    // Add hunks
    for (const hunk of patch.hunks) {
      lines.push(`@@ ${hunk.oldStart},${hunk.oldCount} ${hunk.newStart},${hunk.newCount} @@`);
      
      for (const line of hunk.lines) {
        lines.push(line);
      }
    }
    
    return lines.join('\n');
  }

  private normalizePath(path: string): string {
    // Handle special cases like /dev/null
    if (path === '/dev/null') {
      return '/dev/null';
    }
    
    // Remove leading 'a/', 'b/', or similar prefixes that git diff adds
    return path.replace(/^([ab])\//, '');
  }

  generateSampleDiff(): string {
    const oldCode = `function getUser(id: number): Promise<User> {
  const user = await userService.getUser(id);
  if (!user) {
    throw new Error('User not found');
  }
  return user;
}

interface User {
  id: number;
  name: string;
  email: string;
}`;

    const newCode = `async function getUser(id: number): Promise<User | null> {
  try {
    const user = await userService.getUser(id);
    return user || null;
  } catch (error) {
    console.error('Failed to fetch user:', error);
    return null;
  }
}

interface User {
  id: number;
  name: string;
  email: string;
  createdAt: Date;
  updatedAt: Date;
}`;

    return createTwoFilesPatch(
      'user.service.ts',
      'user.service.ts',
      oldCode,
      newCode,
      'old',
      'new'
    );
  }
}